import type { PrismaClient } from '../../generated/prisma/client.js';

export async function seedMillionaire(prisma: PrismaClient, catMap: Record<string, string>) {
  await prisma.quiz.upsert({
    where: { slug: 'millionaire' },
    update: {
      title: { es: '¿Qué harías si fueras millonario/a?', en: 'What would you do if you were a millionaire?', fr: 'Que feriez-vous si vous étiez millionnaire?', de: 'Was würdest du tun, wenn du Millionär/in wärst?', it: 'Cosa faresti se fossi milionario/a?', pt: 'O que você faria se fosse milionário/a?' },
      description: { es: 'El dinero amplifica quien ya eres. ¿Qué revelaría de ti tener dinero sin límite?', en: 'Money amplifies who you already are. What would having unlimited money reveal about you?', fr: 'L\'argent amplifie qui vous êtes déjà. Que révélerait de vous le fait d\'avoir de l\'argent sans limite?', de: 'Geld verstärkt, wer du bereits bist. Was würde unbegrenztes Geld über dich enthüllen?', it: 'Il denaro amplifica chi sei già. Cosa rivelerebbe di te avere soldi senza limite?', pt: 'O dinheiro amplifica quem você já é. O que ter dinheiro sem limite revelaria de você?' },
      scenarioLabel: { es: 'Decisión', en: 'Decision', fr: 'Décision', de: 'Entscheidung', it: 'Decisione', pt: 'Decisão' },
      dimensionLabels: {
        es: { H: 'Hedonismo', G: 'Generosidad', P: 'Poder', L: 'Legado' },
        en: { H: 'Hedonism', G: 'Generosity', P: 'Power', L: 'Legacy' },
        fr: { H: 'Hédonisme', G: 'Générosité', P: 'Pouvoir', L: 'Héritage' },
        de: { H: 'Hedonismus', G: 'Großzügigkeit', P: 'Macht', L: 'Vermächtnis' },
        it: { H: 'Edonismo', G: 'Generosità', P: 'Potere', L: 'Lascito' },
        pt: { H: 'Hedonismo', G: 'Generosidade', P: 'Poder', L: 'Legado' },
      },
      questions: [
        { id: 1, situation: { es: 'Primera compra con tu nuevo dinero.', en: 'First purchase with your new money.', fr: 'Premier achat avec votre nouvel argent.', de: 'Erster Kauf mit deinem neuen Geld.', it: 'Primo acquisto con il tuo nuovo denaro.', pt: 'Primeira compra com o seu novo dinheiro.' }, options: [{ text: { es: 'Casa de lujo o supercar. Me lo merezco.', en: 'Luxury house or supercar. I deserve it.', fr: 'Maison de luxe ou supercar. Je le mérite.', de: 'Luxushaus oder Sportwagen. Ich verdiene es.', it: 'Casa di lusso o supercar. Me lo merito.', pt: 'Casa de luxo ou supercar. Mereço.' }, dimension: 'H' }, { text: { es: 'Ayuda a mi familia más cercana. Ellos primero.', en: 'Help my closest family. They come first.', fr: 'Aider ma famille la plus proche. Eux d\'abord.', de: 'Meine nächste Familie unterstützen. Sie kommen zuerst.', it: 'Aiuto la mia famiglia più stretta. Prima loro.', pt: 'Ajudo a minha família mais próxima. Eles primeiro.' }, dimension: 'G' }, { text: { es: 'Una inversión que me dé más dinero y más opciones.', en: 'An investment that gives me more money and more options.', fr: 'Un investissement qui me donne plus d\'argent et plus d\'options.', de: 'Eine Investition, die mir mehr Geld und mehr Optionen gibt.', it: 'Un investimento che mi dia più denaro e più opzioni.', pt: 'Um investimento que me dê mais dinheiro e mais opções.' }, dimension: 'P' }, { text: { es: 'Fondear un proyecto que siempre quise hacer pero nunca pude.', en: 'Fund a project I always wanted to do but never could.', fr: 'Financer un projet que j\'ai toujours voulu faire mais que je n\'ai jamais pu.', de: 'Ein Projekt finanzieren, das ich immer machen wollte, aber nie konnte.', it: 'Finanziare un progetto che ho sempre voluto fare ma non ho mai potuto.', pt: 'Financiar um projeto que sempre quis fazer, mas nunca pude.' }, dimension: 'L' }] },
        { id: 2, situation: { es: 'Con ese dinero, ¿cómo manejas la relación con tu círculo actual?', en: 'With that money, how do you manage your relationship with your current circle?', fr: 'Avec cet argent, comment gérez-vous la relation avec votre cercle actuel?', de: 'Mit diesem Geld, wie gehst du mit deiner Beziehung zu deinem aktuellen Umfeld um?', it: 'Con quel denaro, come gestisci il rapporto con la tua cerchia attuale?', pt: 'Com esse dinheiro, como você lida com a relação com o seu círculo atual?' }, options: [{ text: { es: 'Invito a todos, festejo, comparto el lujo con quienes siempre estuvieron.', en: 'I invite everyone, celebrate, share the luxury with those who were always there.', fr: 'J\'invite tout le monde, je fête, je partage le luxe avec ceux qui ont toujours été là.', de: 'Ich lade alle ein, feiere, teile den Luxus mit denen, die immer da waren.', it: 'Invito tutti, festeggio, condivido il lusso con chi è sempre stato presente.', pt: 'Convido a todos, festejo, compartilho o luxo com quem sempre esteve presente.' }, dimension: 'H' }, { text: { es: 'Ayudo activamente a quienes lo necesitan entre mis cercanos.', en: 'I actively help those among my close ones who need it.', fr: 'J\'aide activement ceux qui en ont besoin parmi mes proches.', de: 'Ich helfe aktiv denjenigen unter meinen Nächsten, die es brauchen.', it: 'Aiuto attivamente chi ne ha bisogno tra le mie persone vicine.', pt: 'Ajudo ativamente quem precisa entre os meus próximos.' }, dimension: 'G' }, { text: { es: 'Construyo una red nueva más alineada con mi nuevo nivel.', en: 'I build a new network more aligned with my new level.', fr: 'Je construis un nouveau réseau plus aligné avec mon nouveau niveau.', de: 'Ich baue ein neues Netzwerk auf, das besser zu meinem neuen Niveau passt.', it: 'Costruisco una nuova rete più allineata con il mio nuovo livello.', pt: 'Construo uma nova rede mais alinhada com o meu novo nível.' }, dimension: 'P' }, { text: { es: 'Mantengo mis relaciones pero me proyecto hacia nuevos proyectos con más impacto.', en: 'I maintain my relationships but project myself toward new projects with more impact.', fr: 'Je maintiens mes relations mais je me projette vers de nouveaux projets avec plus d\'impact.', de: 'Ich pflege meine Beziehungen, projiziere mich aber auf neue Projekte mit mehr Wirkung.', it: 'Mantengo le mie relazioni ma mi proietto verso nuovi progetti con più impatto.', pt: 'Mantenho minhas relações, mas me projeto para novos projetos com mais impacto.' }, dimension: 'L' }] },
        { id: 3, situation: { es: 'Te piden que hables públicamente sobre tu dinero. ¿Qué dices?', en: 'You are asked to speak publicly about your money. What do you say?', fr: 'On vous demande de parler publiquement de votre argent. Que dites-vous?', de: 'Man bittet dich, öffentlich über dein Geld zu sprechen. Was sagst du?', it: 'Ti chiedono di parlare pubblicamente dei tuoi soldi. Cosa dici?', pt: 'Pedem que você fale publicamente sobre o seu dinheiro. O que você diz?' }, options: [{ text: { es: 'Muestro el estilo de vida. La transparencia sobre el lujo me parece honesta.', en: 'I show the lifestyle. Transparency about luxury seems honest to me.', fr: 'Je montre le style de vie. La transparence sur le luxe me semble honnête.', de: 'Ich zeige den Lebensstil. Transparenz über Luxus erscheint mir ehrlich.', it: 'Mostro lo stile di vita. La trasparenza sul lusso mi sembra onesta.', pt: 'Mostro o estilo de vida. A transparência sobre o luxo me parece honesta.' }, dimension: 'H' }, { text: { es: 'Hablo de cómo uso el dinero para ayudar a otros.', en: 'I talk about how I use money to help others.', fr: 'Je parle de la façon dont j\'utilise l\'argent pour aider les autres.', de: 'Ich spreche darüber, wie ich Geld nutze, um anderen zu helfen.', it: 'Parlo di come uso il denaro per aiutare gli altri.', pt: 'Falo sobre como uso o dinheiro para ajudar os outros.' }, dimension: 'G' }, { text: { es: 'No hablo mucho. El dinero genera influencia y prefiero usarla con discreción.', en: 'I don\'t say much. Money generates influence and I prefer to use it discreetly.', fr: 'Je ne parle pas beaucoup. L\'argent génère de l\'influence et je préfère l\'utiliser avec discrétion.', de: 'Ich sage nicht viel. Geld erzeugt Einfluss und ich ziehe es vor, ihn mit Diskretion einzusetzen.', it: 'Non parlo molto. Il denaro genera influenza e preferisco usarla con discrezione.', pt: 'Não falo muito. O dinheiro gera influência e prefiro usá-la com discrição.' }, dimension: 'P' }, { text: { es: 'Hablo de los proyectos que estoy construyendo y lo que quiero dejar.', en: 'I talk about the projects I\'m building and what I want to leave behind.', fr: 'Je parle des projets que je construis et de ce que je veux laisser derrière moi.', de: 'Ich spreche über die Projekte, die ich aufbaue, und was ich hinterlassen möchte.', it: 'Parlo dei progetti che sto costruendo e di quello che voglio lasciare.', pt: 'Falo dos projetos que estou construindo e do que quero deixar.' }, dimension: 'L' }] },
        { id: 4, situation: { es: '¿Sigues trabajando?', en: 'Do you keep working?', fr: 'Continuez-vous à travailler?', de: 'Arbeitest du weiter?', it: 'Continui a lavorare?', pt: 'Você continua trabalhando?' }, options: [{ text: { es: 'Trabajo solo en cosas que me dan placer. Nada que no quiera hacer.', en: 'I work only on things that give me pleasure. Nothing I don\'t want to do.', fr: 'Je travaille uniquement sur des choses qui me donnent du plaisir. Rien que je ne veuille pas faire.', de: 'Ich arbeite nur an Dingen, die mir Freude bereiten. Nichts, was ich nicht tun möchte.', it: 'Lavoro solo su cose che mi danno piacere. Niente che non voglio fare.', pt: 'Trabalho apenas no que me dá prazer. Nada que não queira fazer.' }, dimension: 'H' }, { text: { es: 'Trabajo en proyectos que generan impacto y que otros no podrían hacer sin este capital.', en: 'I work on projects that generate impact and that others couldn\'t do without this capital.', fr: 'Je travaille sur des projets qui génèrent un impact et que d\'autres ne pourraient pas faire sans ce capital.', de: 'Ich arbeite an Projekten, die Wirkung erzielen und die andere ohne dieses Kapital nicht tun könnten.', it: 'Lavoro su progetti che generano impatto e che altri non potrebbero fare senza questo capitale.', pt: 'Trabalho em projetos que geram impacto e que outros não poderiam fazer sem esse capital.' }, dimension: 'G' }, { text: { es: 'Trabajo para construir más. El dinero es poder y el poder se construye.', en: 'I work to build more. Money is power and power is built.', fr: 'Je travaille pour construire davantage. L\'argent est pouvoir et le pouvoir se construit.', de: 'Ich arbeite, um mehr aufzubauen. Geld ist Macht und Macht wird aufgebaut.', it: 'Lavoro per costruire di più. Il denaro è potere e il potere si costruisce.', pt: 'Trabalho para construir mais. O dinheiro é poder e o poder se constrói.' }, dimension: 'P' }, { text: { es: 'Trabajo en proyectos de largo plazo que quiero que sobrevivan cuando ya no esté.', en: 'I work on long-term projects that I want to survive when I\'m gone.', fr: 'Je travaille sur des projets à long terme que je veux voir survivre quand je ne serai plus là.', de: 'Ich arbeite an langfristigen Projekten, die ich mir wünsche, dass sie überleben, wenn ich nicht mehr da bin.', it: 'Lavoro su progetti a lungo termine che voglio sopravvivano quando non ci sarò più.', pt: 'Trabalho em projetos de longo prazo que quero que sobrevivam quando não estiver mais aqui.' }, dimension: 'L' }] },
        { id: 5, situation: { es: 'Alguien que te cayó mal en el pasado ahora necesita ayuda.', en: 'Someone you disliked in the past now needs help.', fr: 'Quelqu\'un qui ne vous plaisait pas dans le passé a maintenant besoin d\'aide.', de: 'Jemand, den du in der Vergangenheit nicht mochtest, braucht jetzt Hilfe.', it: 'Qualcuno che non ti piaceva in passato ora ha bisogno di aiuto.', pt: 'Alguém com quem você não se dava bem no passado agora precisa de ajuda.' }, options: [{ text: { es: 'Dependiendo de qué tan mal me cayó, quizás le doy una oportunidad de redención.', en: 'Depending on how much I disliked them, maybe I give them a chance at redemption.', fr: 'Selon à quel point il/elle ne me plaisait pas, peut-être que je lui donne une chance de rédemption.', de: 'Abhängig davon, wie sehr ich sie nicht mochte, gebe ich ihnen vielleicht eine Chance zur Wiedergutmachung.', it: 'A seconda di quanto non mi piaceva, forse gli/le do una possibilità di redenzione.', pt: 'Dependendo do quanto não gostava dela, talvez lhe dê uma oportunidade de redenção.' }, dimension: 'H' }, { text: { es: 'Lo ayudo. El dinero me da la libertad de ser generoso incluso con los que no lo merecen.', en: 'I help them. Money gives me the freedom to be generous even with those who don\'t deserve it.', fr: 'Je l\'aide. L\'argent me donne la liberté d\'être généreux même avec ceux qui ne le méritent pas.', de: 'Ich helfe ihnen. Geld gibt mir die Freiheit, großzügig zu sein, auch gegenüber denen, die es nicht verdienen.', it: 'Lo/La aiuto. Il denaro mi dà la libertà di essere generoso anche con chi non lo merita.', pt: 'Ajudo. O dinheiro me dá a liberdade de ser generoso mesmo com quem não merece.' }, dimension: 'G' }, { text: { es: 'No necesito mezclarme con gente que no me suma.', en: 'I don\'t need to mix with people who don\'t add value to me.', fr: 'Je n\'ai pas besoin de me mêler à des gens qui ne m\'apportent rien.', de: 'Ich muss mich nicht mit Menschen abgeben, die mir nichts geben.', it: 'Non ho bisogno di mescolarmi con persone che non mi apportano nulla.', pt: 'Não preciso me misturar com pessoas que não me acrescentam.' }, dimension: 'P' }, { text: { es: 'Lo evalúo según si tiene algo que ver con mis proyectos.', en: 'I evaluate it based on whether it has anything to do with my projects.', fr: 'Je l\'évalue selon si cela a quelque chose à voir avec mes projets.', de: 'Ich bewerte es danach, ob es etwas mit meinen Projekten zu tun hat.', it: 'Lo valuto in base al se ha qualcosa a che fare con i miei progetti.', pt: 'Avalio conforme se tem alguma relação com meus projetos.' }, dimension: 'L' }] },
        { id: 6, situation: { es: '¿Qué haces con el tiempo que el dinero te libera?', en: 'What do you do with the time that money frees up for you?', fr: 'Que faites-vous avec le temps que l\'argent vous libère?', de: 'Was machst du mit der Zeit, die dir das Geld freisetzt?', it: 'Cosa fai con il tempo che il denaro ti libera?', pt: 'O que você faz com o tempo que o dinheiro te libera?' }, options: [{ text: { es: 'Viajes, experiencias, placeres que siempre quise tener.', en: 'Travel, experiences, pleasures I always wanted to have.', fr: 'Voyages, expériences, plaisirs que j\'ai toujours voulu avoir.', de: 'Reisen, Erlebnisse, Freuden, die ich schon immer haben wollte.', it: 'Viaggi, esperienze, piaceri che ho sempre voluto avere.', pt: 'Viagens, experiências, prazeres que sempre quis ter.' }, dimension: 'H' }, { text: { es: 'Me dedico a personas y causas que necesitan mi tiempo tanto como mi dinero.', en: 'I dedicate myself to people and causes that need my time as much as my money.', fr: 'Je me consacre à des personnes et des causes qui ont autant besoin de mon temps que de mon argent.', de: 'Ich widme mich Menschen und Anliegen, die meine Zeit genauso brauchen wie mein Geld.', it: 'Mi dedico a persone e cause che hanno bisogno del mio tempo tanto quanto del mio denaro.', pt: 'Me dedico a pessoas e causas que precisam do meu tempo tanto quanto do meu dinheiro.' }, dimension: 'G' }, { text: { es: 'Me estrategifico: aprendo, hago contactos, construyo más influencia.', en: 'I strategize: I learn, network, build more influence.', fr: 'Je me stratégise: j\'apprends, je fais des contacts, je construis plus d\'influence.', de: 'Ich strategisiere: Ich lerne, knüpfe Kontakte, baue mehr Einfluss auf.', it: 'Mi stratifico: imparo, faccio contatti, costruisco più influenza.', pt: 'Me estrategifico: aprendo, faço contatos, construo mais influência.' }, dimension: 'P' }, { text: { es: 'Trabajo en el proyecto que quiero dejar como legado.', en: 'I work on the project I want to leave as my legacy.', fr: 'Je travaille sur le projet que je veux laisser en héritage.', de: 'Ich arbeite an dem Projekt, das ich als mein Vermächtnis hinterlassen möchte.', it: 'Lavoro sul progetto che voglio lasciare come eredità.', pt: 'Trabalho no projeto que quero deixar como legado.' }, dimension: 'L' }] },
        { id: 7, situation: { es: '¿Cómo tratas a las personas que trabajan para ti?', en: 'How do you treat the people who work for you?', fr: 'Comment traitez-vous les personnes qui travaillent pour vous?', de: 'Wie behandelst du die Menschen, die für dich arbeiten?', it: 'Come tratti le persone che lavorano per te?', pt: 'Como você trata as pessoas que trabalham para você?' }, options: [{ text: { es: 'Bien, pero claramente somos de mundos diferentes. La jerarquía es real.', en: 'Well, but clearly we are from different worlds. The hierarchy is real.', fr: 'Bien, mais clairement nous sommes de mondes différents. La hiérarchie est réelle.', de: 'Gut, aber wir kommen klar aus verschiedenen Welten. Die Hierarchie ist real.', it: 'Bene, ma chiaramente siamo di mondi diversi. La gerarchia è reale.', pt: 'Bem, mas claramente somos de mundos diferentes. A hierarquia é real.' }, dimension: 'H' }, { text: { es: 'Con mucho respeto y generosidad. El dinero me da la posibilidad de ser un buen empleador.', en: 'With great respect and generosity. Money gives me the possibility of being a good employer.', fr: 'Avec beaucoup de respect et de générosité. L\'argent me donne la possibilité d\'être un bon employeur.', de: 'Mit großem Respekt und Großzügigkeit. Geld gibt mir die Möglichkeit, ein guter Arbeitgeber zu sein.', it: 'Con molto rispetto e generosità. Il denaro mi dà la possibilità di essere un buon datore di lavoro.', pt: 'Com muito respeito e generosidade. O dinheiro me dá a possibilidade de ser um bom empregador.' }, dimension: 'G' }, { text: { es: 'Con respeto profesional. La relación es transaccional y está bien que lo sea.', en: 'With professional respect. The relationship is transactional and that\'s fine.', fr: 'Avec respect professionnel. La relation est transactionnelle et c\'est bien ainsi.', de: 'Mit professionellem Respekt. Die Beziehung ist transaktional und das ist in Ordnung.', it: 'Con rispetto professionale. Il rapporto è transazionale ed è giusto che lo sia.', pt: 'Com respeito profissional. A relação é transacional e tudo bem que seja assim.' }, dimension: 'P' }, { text: { es: 'Como socios en algo que quiero que dure. Su bienestar importa para el proyecto.', en: 'As partners in something I want to last. Their wellbeing matters for the project.', fr: 'Comme des associés dans quelque chose que je veux voir durer. Leur bien-être compte pour le projet.', de: 'Als Partner in etwas, das ich dauerhaft haben möchte. Ihr Wohlbefinden ist wichtig für das Projekt.', it: 'Come soci in qualcosa che voglio duri. Il loro benessere conta per il progetto.', pt: 'Como sócios em algo que quero que dure. O bem-estar deles importa para o projeto.' }, dimension: 'L' }] },
        { id: 8, situation: { es: '¿Cuánto de tu fortuna vas a donar?', en: 'How much of your fortune are you going to donate?', fr: 'Combien de votre fortune allez-vous donner?', de: 'Wie viel von deinem Vermögen wirst du spenden?', it: 'Quanto della tua fortuna donerai?', pt: 'Quanto da sua fortuna você vai doar?' }, options: [{ text: { es: 'Algo simbólico. No soy una ONG.', en: 'Something symbolic. I\'m not an NGO.', fr: 'Quelque chose de symbolique. Je ne suis pas une ONG.', de: 'Etwas Symbolisches. Ich bin keine NGO.', it: 'Qualcosa di simbolico. Non sono una ONG.', pt: 'Algo simbólico. Não sou uma ONG.' }, dimension: 'H' }, { text: { es: 'Una parte significativa. Con tanto dinero, sería inmoral no hacerlo.', en: 'A significant portion. With so much money, it would be immoral not to.', fr: 'Une partie significative. Avec autant d\'argent, ne pas le faire serait immoral.', de: 'Ein erheblicher Teil. Mit so viel Geld wäre es unmoralisch, es nicht zu tun.', it: 'Una parte significativa. Con così tanti soldi, sarebbe immorale non farlo.', pt: 'Uma parte significativa. Com tanto dinheiro, seria imoral não fazê-lo.' }, dimension: 'G' }, { text: { es: 'Lo necesario para tener buena reputación pública.', en: 'Enough to maintain a good public reputation.', fr: 'Le nécessaire pour avoir une bonne réputation publique.', de: 'Das Nötige, um einen guten öffentlichen Ruf zu haben.', it: 'Quanto basta per avere una buona reputazione pubblica.', pt: 'O necessário para ter boa reputação pública.' }, dimension: 'P' }, { text: { es: 'Una parte grande pero en causas específicas que elijo con criterio.', en: 'A large portion but to specific causes I choose deliberately.', fr: 'Une grande partie mais pour des causes spécifiques que je choisis avec discernement.', de: 'Ein großer Teil, aber für spezifische Anliegen, die ich gezielt auswähle.', it: 'Una parte grande ma per cause specifiche che scelgo con criterio.', pt: 'Uma parte grande, mas para causas específicas que escolho com critério.' }, dimension: 'L' }] },
        { id: 9, situation: { es: 'Una persona te pide dinero para un proyecto que no te convence.', en: 'Someone asks you for money for a project you\'re not convinced by.', fr: 'Une personne vous demande de l\'argent pour un projet qui ne vous convainc pas.', de: 'Jemand bittet dich um Geld für ein Projekt, das dich nicht überzeugt.', it: 'Una persona ti chiede soldi per un progetto che non ti convince.', pt: 'Uma pessoa te pede dinheiro para um projeto que não te convence.' }, options: [{ text: { es: 'No lo financio. Prefiero gastar mi dinero en cosas que disfruto.', en: 'I don\'t fund it. I prefer to spend my money on things I enjoy.', fr: 'Je ne le finance pas. Je préfère dépenser mon argent sur des choses que j\'apprécie.', de: 'Ich finanziere es nicht. Ich gebe mein Geld lieber für Dinge aus, die ich genieße.', it: 'Non lo finanzo. Preferisco spendere i miei soldi in cose che mi piacciono.', pt: 'Não financio. Prefiro gastar meu dinheiro em coisas que disfruto.' }, dimension: 'H' }, { text: { es: 'Le doy algo de todas formas. La generosidad no siempre requiere convencerse.', en: 'I give them something anyway. Generosity doesn\'t always require being convinced.', fr: 'Je lui donne quelque chose quand même. La générosité ne nécessite pas toujours d\'être convaincu.', de: 'Ich gebe ihnen trotzdem etwas. Großzügigkeit erfordert nicht immer Überzeugung.', it: 'Gli/Le do qualcosa comunque. La generosità non richiede sempre di essere convinti.', pt: 'Dou algo de qualquer maneira. A generosidade nem sempre requer convencimento.' }, dimension: 'G' }, { text: { es: 'No lo financio. Mi dinero va a proyectos que controlo.', en: 'I don\'t fund it. My money goes to projects I control.', fr: 'Je ne le finance pas. Mon argent va à des projets que je contrôle.', de: 'Ich finanziere es nicht. Mein Geld fließt in Projekte, die ich kontrolliere.', it: 'Non lo finanzo. I miei soldi vanno a progetti che controllo.', pt: 'Não financio. Meu dinheiro vai para projetos que controlo.' }, dimension: 'P' }, { text: { es: 'No lo financio, pero le explico por qué y le ofrezco feedback si le sirve.', en: 'I don\'t fund it, but I explain why and offer feedback if it\'s useful to them.', fr: 'Je ne le finance pas, mais je lui explique pourquoi et je lui offre des commentaires si cela lui est utile.', de: 'Ich finanziere es nicht, aber ich erkläre, warum, und biete Feedback an, wenn es nützlich ist.', it: 'Non lo finanzo, ma spiego perché e offro feedback se gli/le è utile.', pt: 'Não financio, mas explico o motivo e ofereço feedback se for útil.' }, dimension: 'L' }] },
        { id: 10, situation: { es: 'En tu vejez, ¿qué hiciste con tu dinero?', en: 'In your old age, what did you do with your money?', fr: 'Dans votre vieillesse, qu\'avez-vous fait avec votre argent?', de: 'In deinem Alter, was hast du mit deinem Geld gemacht?', it: 'Nella tua vecchiaia, cosa hai fatto con i tuoi soldi?', pt: 'Na sua velhice, o que você fez com o seu dinheiro?' }, options: [{ text: { es: 'Viví extraordinariamente bien. Cada placer que quise, lo tuve.', en: 'I lived extraordinarily well. Every pleasure I wanted, I had.', fr: 'J\'ai vécu extraordinairement bien. Chaque plaisir que je voulais, je l\'ai eu.', de: 'Ich lebte außerordentlich gut. Jedes Vergnügen, das ich wollte, hatte ich.', it: 'Ho vissuto straordinariamente bene. Ogni piacere che ho voluto, l\'ho avuto.', pt: 'Vivi extraordinariamente bem. Cada prazer que quis, tive.' }, dimension: 'H' }, { text: { es: 'Cambié la vida de personas concretas que nunca olvidaré.', en: 'I changed the lives of specific people I will never forget.', fr: 'J\'ai changé la vie de personnes concrètes que je n\'oublierai jamais.', de: 'Ich veränderte das Leben konkreter Menschen, die ich niemals vergessen werde.', it: 'Ho cambiato la vita di persone concrete che non dimenticherò mai.', pt: 'Mudei a vida de pessoas concretas que nunca esquecerei.' }, dimension: 'G' }, { text: { es: 'Construí algo que tiene influencia real sobre cómo funciona el mundo.', en: 'I built something that has real influence over how the world works.', fr: 'J\'ai construit quelque chose qui a une influence réelle sur le fonctionnement du monde.', de: 'Ich habe etwas aufgebaut, das realen Einfluss darauf hat, wie die Welt funktioniert.', it: 'Ho costruito qualcosa che ha influenza reale su come funziona il mondo.', pt: 'Construí algo que tem influência real sobre como o mundo funciona.' }, dimension: 'P' }, { text: { es: 'Dejé algo que sobrevive: una fundación, una empresa, una obra que importa.', en: 'I left something that survives: a foundation, a company, a work that matters.', fr: 'J\'ai laissé quelque chose qui survit: une fondation, une entreprise, une œuvre qui compte.', de: 'Ich habe etwas hinterlassen, das überlebt: eine Stiftung, ein Unternehmen, ein Werk, das Bedeutung hat.', it: 'Ho lasciato qualcosa che sopravvive: una fondazione, un\'impresa, un\'opera che conta.', pt: 'Deixei algo que sobrevive: uma fundação, uma empresa, uma obra que importa.' }, dimension: 'L' }] },
      ],
      characters: [
        { name: { es: 'El Epicúreo Rico', en: 'The Wealthy Epicurean', fr: 'L\'Épicurien Riche', de: 'Der Wohlhabende Epikureer', it: 'L\'Epicureo Ricco', pt: 'O Epicurista Rico' }, dimensions: ['H'], photo: '/characters/epicurean-rich.jpg', description: { es: 'El dinero existe para disfrutarlo. Sin disculpas.', en: 'Money exists to be enjoyed. No apologies.', fr: 'L\'argent existe pour être apprécié. Sans excuses.', de: 'Geld existiert, um genossen zu werden. Ohne Entschuldigungen.', it: 'Il denaro esiste per essere goduto. Senza scuse.', pt: 'O dinheiro existe para ser desfrutado. Sem desculpas.' }, philosophy: { es: 'Para ti, el dinero es la herramienta definitiva del placer. No te disculpas por ello. Viviste un tiempo sin esos recursos — ahora que los tienes, los disfrutas. La única pregunta que vale es si eso te hace feliz.', en: 'For you, money is the ultimate tool of pleasure. You don\'t apologize for it. You lived for a time without those resources — now that you have them, you enjoy them. The only question that matters is whether that makes you happy.', fr: 'Pour vous, l\'argent est l\'outil ultime du plaisir. Vous ne vous en excusez pas. Vous avez vécu un temps sans ces ressources — maintenant que vous les avez, vous en profitez. La seule question qui vaille est de savoir si cela vous rend heureux.', de: 'Für dich ist Geld das ultimative Werkzeug des Genusses. Du entschuldigst dich nicht dafür. Du hast eine Zeit ohne diese Mittel gelebt — jetzt, da du sie hast, genießt du sie. Die einzige Frage, die zählt, ist, ob dich das glücklich macht.', it: 'Per te, il denaro è lo strumento definitivo del piacere. Non ti scusi per questo. Hai vissuto per un periodo senza quelle risorse — ora che le hai, le godi. La sola domanda che conta è se questo ti rende felice.', pt: 'Para você, o dinheiro é a ferramenta definitiva do prazer. Você não se desculpa por isso. Você viveu um tempo sem esses recursos — agora que os tem, os desfruta. A única questão que vale é se isso te faz feliz.' } },
        { name: { es: 'El Filántropo Auténtico', en: 'The Authentic Philanthropist', fr: 'Le Philanthrope Authentique', de: 'Der Authentische Philanthrop', it: 'Il Filantropo Autentico', pt: 'O Filantropo Autêntico' }, dimensions: ['G'], photo: '/characters/authentic-philanthropist.jpg', description: { es: 'El dinero solo tiene sentido si cambia vidas ajenas.', en: 'Money only makes sense if it changes other people\'s lives.', fr: 'L\'argent n\'a de sens que s\'il change la vie des autres.', de: 'Geld macht nur Sinn, wenn es das Leben anderer verändert.', it: 'Il denaro ha senso solo se cambia la vita degli altri.', pt: 'O dinheiro só faz sentido se mudar a vida dos outros.' }, philosophy: { es: 'Para ti, acumular riqueza sin distribuirla es una forma de fracaso. No porque sea una obligación — sino porque la generosidad te da un placer real. Ver el impacto concreto de tu dinero vale más que cualquier lujo.', en: 'For you, accumulating wealth without distributing it is a form of failure. Not because it\'s an obligation — but because generosity gives you real pleasure. Seeing the concrete impact of your money is worth more than any luxury.', fr: 'Pour vous, accumuler de la richesse sans la distribuer est une forme d\'échec. Non pas parce que c\'est une obligation — mais parce que la générosité vous procure un plaisir réel. Voir l\'impact concret de votre argent vaut plus que n\'importe quel luxe.', de: 'Für dich ist das Anhäufen von Reichtum ohne ihn zu verteilen eine Form des Scheiterns. Nicht weil es eine Pflicht ist — sondern weil Großzügigkeit dir echte Freude bereitet. Den konkreten Impact deines Geldes zu sehen ist mehr wert als jeder Luxus.', it: 'Per te, accumulare ricchezza senza distribuirla è una forma di fallimento. Non perché sia un obbligo — ma perché la generosità ti dà un piacere reale. Vedere l\'impatto concreto del tuo denaro vale più di qualsiasi lusso.', pt: 'Para você, acumular riqueza sem distribuí-la é uma forma de fracasso. Não porque seja uma obrigação — mas porque a generosidade te dá um prazer real. Ver o impacto concreto do seu dinheiro vale mais do que qualquer luxo.' } },
        { name: { es: 'El Constructor de Poder', en: 'The Power Builder', fr: 'Le Constructeur de Pouvoir', de: 'Der Machtbauer', it: 'Il Costruttore di Potere', pt: 'O Construtor de Poder' }, dimensions: ['P'], photo: '/characters/power-builder.jpg', description: { es: 'El dinero es el primer escalón. El poder es el destino.', en: 'Money is the first step. Power is the destination.', fr: 'L\'argent est le premier échelon. Le pouvoir est la destination.', de: 'Geld ist die erste Stufe. Macht ist das Ziel.', it: 'Il denaro è il primo scalino. Il potere è la destinazione.', pt: 'O dinheiro é o primeiro degrau. O poder é o destino.' }, philosophy: { es: 'Para ti, el dinero es un medio, no un fin. Lo que buscas es influencia real sobre cómo funcionan las cosas. Eso puede ser bueno o problemático, dependiendo de qué hagas con ese poder.', en: 'For you, money is a means, not an end. What you seek is real influence over how things work. That can be good or problematic, depending on what you do with that power.', fr: 'Pour vous, l\'argent est un moyen, pas une fin. Ce que vous cherchez, c\'est une influence réelle sur le fonctionnement des choses. Cela peut être bien ou problématique, selon ce que vous faites de ce pouvoir.', de: 'Für dich ist Geld ein Mittel, kein Zweck. Was du suchst, ist realer Einfluss darauf, wie die Dinge funktionieren. Das kann gut oder problematisch sein, je nachdem, was du mit dieser Macht machst.', it: 'Per te, il denaro è un mezzo, non un fine. Quello che cerchi è influenza reale su come funzionano le cose. Questo può essere buono o problematico, a seconda di cosa fai con quel potere.', pt: 'Para você, o dinheiro é um meio, não um fim. O que você busca é influência real sobre como as coisas funcionam. Isso pode ser bom ou problemático, dependendo do que você faz com esse poder.' } },
        { name: { es: 'El Arquitecto del Legado', en: 'The Legacy Architect', fr: 'L\'Architecte de l\'Héritage', de: 'Der Vermächtnis-Architekt', it: 'L\'Architetto del Lascito', pt: 'O Arquiteto do Legado' }, dimensions: ['L'], photo: '/characters/legacy-architect.jpg', description: { es: 'Construye para que algo suyo sobreviva cuando ya no esté.', en: 'Builds so that something of theirs survives when they are gone.', fr: 'Construit pour que quelque chose de lui/elle survive quand il/elle ne sera plus là.', de: 'Baut, damit etwas von ihm/ihr überlebt, wenn er/sie nicht mehr da ist.', it: 'Costruisce perché qualcosa di suo sopravviva quando non ci sarà più.', pt: 'Constrói para que algo seu sobreviva quando não estiver mais aqui.' }, philosophy: { es: 'Para ti, la verdadera riqueza es dejar algo que dure. No una fortuna heredada — una obra, un sistema, una idea que siga funcionando cuando ya no estés. Esa es la única forma de inmortalidad que te parece real.', en: 'For you, true wealth is leaving something that lasts. Not an inherited fortune — a work, a system, an idea that keeps functioning when you\'re gone. That is the only form of immortality that seems real to you.', fr: 'Pour vous, la vraie richesse consiste à laisser quelque chose qui dure. Pas une fortune héritée — une œuvre, un système, une idée qui continue à fonctionner quand vous ne serez plus là. C\'est la seule forme d\'immortalité qui vous semble réelle.', de: 'Für dich ist der wahre Reichtum, etwas zu hinterlassen, das dauert. Kein geerbtes Vermögen — ein Werk, ein System, eine Idee, die weiter funktioniert, wenn du nicht mehr da bist. Das ist die einzige Form der Unsterblichkeit, die dir real erscheint.', it: 'Per te, la vera ricchezza è lasciare qualcosa che duri. Non una fortuna ereditata — un\'opera, un sistema, un\'idea che continui a funzionare quando non ci sarai più. Questa è la sola forma di immortalità che ti sembra reale.', pt: 'Para você, a verdadeira riqueza é deixar algo que dure. Não uma fortuna herdada — uma obra, um sistema, uma ideia que continue funcionando quando você não estiver mais aqui. Essa é a única forma de imortalidade que lhe parece real.' } },
        { name: { es: 'El Hedonista Generoso', en: 'The Generous Hedonist', fr: 'L\'Hédoniste Généreux', de: 'Der Großzügige Hedonist', it: 'L\'Edonista Generoso', pt: 'O Hedonista Generoso' }, dimensions: ['H', 'G'], photo: '/characters/hedonist-generous.jpg', description: { es: 'Vive bien y ayuda a que otros vivan bien.', en: 'Lives well and helps others live well.', fr: 'Vit bien et aide les autres à bien vivre.', de: 'Lebt gut und hilft anderen, gut zu leben.', it: 'Vive bene e aiuta gli altri a vivere bene.', pt: 'Vive bem e ajuda os outros a viverem bem.' }, philosophy: { es: 'No hay contradicción entre disfrutar y dar. Disfrutas tu dinero sin culpa y también lo distribuyes sin renunciar. Esa combinación requiere dinero suficiente y también una claridad sobre cuánto es suficiente para uno mismo.', en: 'There is no contradiction between enjoying and giving. You enjoy your money without guilt and also distribute it without giving it all up. That combination requires enough money and also clarity about how much is enough for oneself.', fr: 'Il n\'y a pas de contradiction entre jouir et donner. Vous profitez de votre argent sans culpabilité et le distribuez aussi sans y renoncer. Cette combinaison nécessite suffisamment d\'argent et aussi une clarté sur ce qui est suffisant pour soi-même.', de: 'Es gibt keinen Widerspruch zwischen Genießen und Geben. Du genießt dein Geld ohne Schuldgefühle und verteilst es auch ohne Verzicht. Diese Kombination erfordert genug Geld und auch Klarheit darüber, was für einen selbst genug ist.', it: 'Non c\'è contraddizione tra godere e dare. Godi del tuo denaro senza sensi di colpa e lo distribuisci anche senza rinunciare. Questa combinazione richiede denaro sufficiente e anche chiarezza su quanto è abbastanza per se stessi.', pt: 'Não há contradição entre desfrutar e dar. Você desfruta do seu dinheiro sem culpa e também o distribui sem renunciar. Essa combinação requer dinheiro suficiente e também clareza sobre quanto é o suficiente para si mesmo.' } },
        { name: { es: 'El Poderoso Generoso', en: 'The Generous Powerful', fr: 'Le Puissant Généreux', de: 'Der Großzügige Mächtige', it: 'Il Potente Generoso', pt: 'O Poderoso Generoso' }, dimensions: ['G', 'P'], photo: '/characters/powerful-generous.jpg', description: { es: 'Usa el poder para generar impacto a mayor escala.', en: 'Uses power to generate impact on a larger scale.', fr: 'Utilise le pouvoir pour générer un impact à plus grande échelle.', de: 'Nutzt Macht, um Wirkung in größerem Maßstab zu erzielen.', it: 'Usa il potere per generare impatto su scala maggiore.', pt: 'Usa o poder para gerar impacto em maior escala.' }, philosophy: { es: 'Para ti, la generosidad más eficiente requiere poder. No es suficiente dar dinero — es necesario tener influencia sobre los sistemas que perpetúan la desigualdad. El poder como herramienta del bien.', en: 'For you, the most efficient generosity requires power. It\'s not enough to give money — you need to have influence over the systems that perpetuate inequality. Power as a tool for good.', fr: 'Pour vous, la générosité la plus efficace nécessite du pouvoir. Il ne suffit pas de donner de l\'argent — il est nécessaire d\'avoir de l\'influence sur les systèmes qui perpétuent l\'inégalité. Le pouvoir comme outil du bien.', de: 'Für dich erfordert die effizienteste Großzügigkeit Macht. Es reicht nicht, Geld zu geben — du musst Einfluss auf die Systeme haben, die Ungleichheit aufrechterhalten. Macht als Werkzeug des Guten.', it: 'Per te, la generosità più efficiente richiede potere. Non basta dare denaro — è necessario avere influenza sui sistemi che perpetuano la disuguaglianza. Il potere come strumento del bene.', pt: 'Para você, a generosidade mais eficiente requer poder. Não basta dar dinheiro — é necessário ter influência sobre os sistemas que perpetuam a desigualdade. O poder como ferramenta do bem.' } },
        { name: { es: 'El Constructor de Sistemas', en: 'The Systems Builder', fr: 'Le Constructeur de Systèmes', de: 'Der Systemerbauer', it: 'Il Costruttore di Sistemi', pt: 'O Construtor de Sistemas' }, dimensions: ['P', 'L'], photo: '/characters/systems-builder.jpg', description: { es: 'Construye estructuras que generan poder e impacto duradero.', en: 'Builds structures that generate power and lasting impact.', fr: 'Construit des structures qui génèrent du pouvoir et un impact durable.', de: 'Baut Strukturen auf, die Macht und dauerhaften Impact erzeugen.', it: 'Costruisce strutture che generano potere e impatto duraturo.', pt: 'Constrói estruturas que geram poder e impacto duradouro.' }, philosophy: { es: 'Combinas la ambición de poder con la visión de largo plazo. No te interesa el impacto inmediato — te interesa construir algo que siga funcionando cuando ya no estés para verlo.', en: 'You combine the ambition for power with a long-term vision. You\'re not interested in immediate impact — you\'re interested in building something that keeps working when you\'re no longer there to see it.', fr: 'Vous combinez l\'ambition du pouvoir avec la vision à long terme. Ce n\'est pas l\'impact immédiat qui vous intéresse — c\'est construire quelque chose qui continue à fonctionner quand vous ne serez plus là pour le voir.', de: 'Du kombinierst den Machtehrgeiz mit der langfristigen Vision. Du interessierst dich nicht für unmittelbare Wirkung — du interessierst dich dafür, etwas aufzubauen, das weiter funktioniert, wenn du nicht mehr da bist, um es zu sehen.', it: 'Combini l\'ambizione di potere con la visione a lungo termine. Non ti interessa l\'impatto immediato — ti interessa costruire qualcosa che continui a funzionare quando non ci sarai più per vederlo.', pt: 'Você combina a ambição de poder com a visão de longo prazo. Não lhe interessa o impacto imediato — lhe interessa construir algo que continue funcionando quando você não estiver mais aqui para vê-lo.' } },
        { name: { es: 'El Filántropo con Legado', en: 'The Philanthropist with a Legacy', fr: 'Le Philanthrope avec un Héritage', de: 'Der Philanthrop mit Vermächtnis', it: 'Il Filantropo con un Lascito', pt: 'O Filantropo com Legado' }, dimensions: ['G', 'L'], photo: '/characters/philanthropist-legacy.jpg', description: { es: 'Genera impacto ahora y construye para que ese impacto dure.', en: 'Creates impact now and builds so that impact lasts.', fr: 'Génère un impact maintenant et construit pour que cet impact dure.', de: 'Erzeugt jetzt Wirkung und baut, damit diese Wirkung dauert.', it: 'Genera impatto ora e costruisce affinché quell\'impatto duri.', pt: 'Gera impacto agora e constrói para que esse impacto dure.' }, philosophy: { es: 'Tu generosidad no es espontánea — es estratégica. No es fría — es efectiva. Quieres que el bien que haces con tu dinero sobreviva y se multiplique. Eso requiere tanto corazón como cabeza.', en: 'Your generosity is not spontaneous — it\'s strategic. It\'s not cold — it\'s effective. You want the good you do with your money to survive and multiply. That requires both heart and mind.', fr: 'Votre générosité n\'est pas spontanée — elle est stratégique. Elle n\'est pas froide — elle est efficace. Vous voulez que le bien que vous faites avec votre argent survive et se multiplie. Cela nécessite autant de cœur que de tête.', de: 'Deine Großzügigkeit ist nicht spontan — sie ist strategisch. Sie ist nicht kalt — sie ist effektiv. Du willst, dass das Gute, das du mit deinem Geld tust, überlebt und sich multipliziert. Das erfordert sowohl Herz als auch Verstand.', it: 'La tua generosità non è spontanea — è strategica. Non è fredda — è efficace. Vuoi che il bene che fai con il tuo denaro sopravviva e si moltiplichi. Ciò richiede sia cuore che mente.', pt: 'Sua generosidade não é espontânea — é estratégica. Não é fria — é eficaz. Você quer que o bem que faz com o seu dinheiro sobreviva e se multiplique. Isso requer tanto coração quanto cabeça.' } },
      ],
    },
    create: {
      slug: 'millionaire',
      title: { es: '¿Qué harías si fueras millonario/a?', en: 'What would you do if you were a millionaire?', fr: 'Que feriez-vous si vous étiez millionnaire?', de: 'Was würdest du tun, wenn du Millionär/in wärst?', it: 'Cosa faresti se fossi milionario/a?', pt: 'O que você faria se fosse milionário/a?' },
      description: { es: 'El dinero amplifica quien ya eres. ¿Qué revelaría de ti tener dinero sin límite?', en: 'Money amplifies who you already are. What would having unlimited money reveal about you?', fr: 'L\'argent amplifie qui vous êtes déjà. Que révélerait de vous le fait d\'avoir de l\'argent sans limite?', de: 'Geld verstärkt, wer du bereits bist. Was würde unbegrenztes Geld über dich enthüllen?', it: 'Il denaro amplifica chi sei già. Cosa rivelerebbe di te avere soldi senza limite?', pt: 'O dinheiro amplifica quem você já é. O que ter dinheiro sem limite revelaria de você?' },
      scenarioLabel: { es: 'Decisión', en: 'Decision', fr: 'Décision', de: 'Entscheidung', it: 'Decisione', pt: 'Decisão' },
      categoryId: catMap['pop-culture'],
      sortOrder: 5,
      dimensionLabels: {
        es: { H: 'Hedonismo', G: 'Generosidad', P: 'Poder', L: 'Legado' },
        en: { H: 'Hedonism', G: 'Generosity', P: 'Power', L: 'Legacy' },
        fr: { H: 'Hédonisme', G: 'Générosité', P: 'Pouvoir', L: 'Héritage' },
        de: { H: 'Hedonismus', G: 'Großzügigkeit', P: 'Macht', L: 'Vermächtnis' },
        it: { H: 'Edonismo', G: 'Generosità', P: 'Potere', L: 'Lascito' },
        pt: { H: 'Hedonismo', G: 'Generosidade', P: 'Poder', L: 'Legado' },
      },
      questions: [
        { id: 1, situation: { es: 'Primera compra con tu nuevo dinero.', en: 'First purchase with your new money.', fr: 'Premier achat avec votre nouvel argent.', de: 'Erster Kauf mit deinem neuen Geld.', it: 'Primo acquisto con il tuo nuovo denaro.', pt: 'Primeira compra com o seu novo dinheiro.' }, options: [{ text: { es: 'Casa de lujo o supercar. Me lo merezco.', en: 'Luxury house or supercar. I deserve it.', fr: 'Maison de luxe ou supercar. Je le mérite.', de: 'Luxushaus oder Sportwagen. Ich verdiene es.', it: 'Casa di lusso o supercar. Me lo merito.', pt: 'Casa de luxo ou supercar. Mereço.' }, dimension: 'H' }, { text: { es: 'Ayuda a mi familia más cercana. Ellos primero.', en: 'Help my closest family. They come first.', fr: 'Aider ma famille la plus proche. Eux d\'abord.', de: 'Meine nächste Familie unterstützen. Sie kommen zuerst.', it: 'Aiuto la mia famiglia più stretta. Prima loro.', pt: 'Ajudo a minha família mais próxima. Eles primeiro.' }, dimension: 'G' }, { text: { es: 'Una inversión que me dé más dinero y más opciones.', en: 'An investment that gives me more money and more options.', fr: 'Un investissement qui me donne plus d\'argent et plus d\'options.', de: 'Eine Investition, die mir mehr Geld und mehr Optionen gibt.', it: 'Un investimento che mi dia più denaro e più opzioni.', pt: 'Um investimento que me dê mais dinheiro e mais opções.' }, dimension: 'P' }, { text: { es: 'Fondear un proyecto que siempre quise hacer pero nunca pude.', en: 'Fund a project I always wanted to do but never could.', fr: 'Financer un projet que j\'ai toujours voulu faire mais que je n\'ai jamais pu.', de: 'Ein Projekt finanzieren, das ich immer machen wollte, aber nie konnte.', it: 'Finanziare un progetto che ho sempre voluto fare ma non ho mai potuto.', pt: 'Financiar um projeto que sempre quis fazer, mas nunca pude.' }, dimension: 'L' }] },
        { id: 2, situation: { es: 'Con ese dinero, ¿cómo manejas la relación con tu círculo actual?', en: 'With that money, how do you manage your relationship with your current circle?', fr: 'Avec cet argent, comment gérez-vous la relation avec votre cercle actuel?', de: 'Mit diesem Geld, wie gehst du mit deiner Beziehung zu deinem aktuellen Umfeld um?', it: 'Con quel denaro, come gestisci il rapporto con la tua cerchia attuale?', pt: 'Com esse dinheiro, como você lida com a relação com o seu círculo atual?' }, options: [{ text: { es: 'Invito a todos, festejo, comparto el lujo con quienes siempre estuvieron.', en: 'I invite everyone, celebrate, share the luxury with those who were always there.', fr: 'J\'invite tout le monde, je fête, je partage le luxe avec ceux qui ont toujours été là.', de: 'Ich lade alle ein, feiere, teile den Luxus mit denen, die immer da waren.', it: 'Invito tutti, festeggio, condivido il lusso con chi è sempre stato presente.', pt: 'Convido a todos, festejo, compartilho o luxo com quem sempre esteve presente.' }, dimension: 'H' }, { text: { es: 'Ayudo activamente a quienes lo necesitan entre mis cercanos.', en: 'I actively help those among my close ones who need it.', fr: 'J\'aide activement ceux qui en ont besoin parmi mes proches.', de: 'Ich helfe aktiv denjenigen unter meinen Nächsten, die es brauchen.', it: 'Aiuto attivamente chi ne ha bisogno tra le mie persone vicine.', pt: 'Ajudo ativamente quem precisa entre os meus próximos.' }, dimension: 'G' }, { text: { es: 'Construyo una red nueva más alineada con mi nuevo nivel.', en: 'I build a new network more aligned with my new level.', fr: 'Je construis un nouveau réseau plus aligné avec mon nouveau niveau.', de: 'Ich baue ein neues Netzwerk auf, das besser zu meinem neuen Niveau passt.', it: 'Costruisco una nuova rete più allineata con il mio nuovo livello.', pt: 'Construo uma nova rede mais alinhada com o meu novo nível.' }, dimension: 'P' }, { text: { es: 'Mantengo mis relaciones pero me proyecto hacia nuevos proyectos con más impacto.', en: 'I maintain my relationships but project myself toward new projects with more impact.', fr: 'Je maintiens mes relations mais je me projette vers de nouveaux projets avec plus d\'impact.', de: 'Ich pflege meine Beziehungen, projiziere mich aber auf neue Projekte mit mehr Wirkung.', it: 'Mantengo le mie relazioni ma mi proietto verso nuovi progetti con più impatto.', pt: 'Mantenho minhas relações, mas me projeto para novos projetos com mais impacto.' }, dimension: 'L' }] },
        { id: 3, situation: { es: 'Te piden que hables públicamente sobre tu dinero. ¿Qué dices?', en: 'You are asked to speak publicly about your money. What do you say?', fr: 'On vous demande de parler publiquement de votre argent. Que dites-vous?', de: 'Man bittet dich, öffentlich über dein Geld zu sprechen. Was sagst du?', it: 'Ti chiedono di parlare pubblicamente dei tuoi soldi. Cosa dici?', pt: 'Pedem que você fale publicamente sobre o seu dinheiro. O que você diz?' }, options: [{ text: { es: 'Muestro el estilo de vida. La transparencia sobre el lujo me parece honesta.', en: 'I show the lifestyle. Transparency about luxury seems honest to me.', fr: 'Je montre le style de vie. La transparence sur le luxe me semble honnête.', de: 'Ich zeige den Lebensstil. Transparenz über Luxus erscheint mir ehrlich.', it: 'Mostro lo stile di vita. La trasparenza sul lusso mi sembra onesta.', pt: 'Mostro o estilo de vida. A transparência sobre o luxo me parece honesta.' }, dimension: 'H' }, { text: { es: 'Hablo de cómo uso el dinero para ayudar a otros.', en: 'I talk about how I use money to help others.', fr: 'Je parle de la façon dont j\'utilise l\'argent pour aider les autres.', de: 'Ich spreche darüber, wie ich Geld nutze, um anderen zu helfen.', it: 'Parlo di come uso il denaro per aiutare gli altri.', pt: 'Falo sobre como uso o dinheiro para ajudar os outros.' }, dimension: 'G' }, { text: { es: 'No hablo mucho. El dinero genera influencia y prefiero usarla con discreción.', en: 'I don\'t say much. Money generates influence and I prefer to use it discreetly.', fr: 'Je ne parle pas beaucoup. L\'argent génère de l\'influence et je préfère l\'utiliser avec discrétion.', de: 'Ich sage nicht viel. Geld erzeugt Einfluss und ich ziehe es vor, ihn mit Diskretion einzusetzen.', it: 'Non parlo molto. Il denaro genera influenza e preferisco usarla con discrezione.', pt: 'Não falo muito. O dinheiro gera influência e prefiro usá-la com discrição.' }, dimension: 'P' }, { text: { es: 'Hablo de los proyectos que estoy construyendo y lo que quiero dejar.', en: 'I talk about the projects I\'m building and what I want to leave behind.', fr: 'Je parle des projets que je construis et de ce que je veux laisser derrière moi.', de: 'Ich spreche über die Projekte, die ich aufbaue, und was ich hinterlassen möchte.', it: 'Parlo dei progetti che sto costruendo e di quello che voglio lasciare.', pt: 'Falo dos projetos que estou construindo e do que quero deixar.' }, dimension: 'L' }] },
        { id: 4, situation: { es: '¿Sigues trabajando?', en: 'Do you keep working?', fr: 'Continuez-vous à travailler?', de: 'Arbeitest du weiter?', it: 'Continui a lavorare?', pt: 'Você continua trabalhando?' }, options: [{ text: { es: 'Trabajo solo en cosas que me dan placer. Nada que no quiera hacer.', en: 'I work only on things that give me pleasure. Nothing I don\'t want to do.', fr: 'Je travaille uniquement sur des choses qui me donnent du plaisir. Rien que je ne veuille pas faire.', de: 'Ich arbeite nur an Dingen, die mir Freude bereiten. Nichts, was ich nicht tun möchte.', it: 'Lavoro solo su cose che mi danno piacere. Niente che non voglio fare.', pt: 'Trabalho apenas no que me dá prazer. Nada que não queira fazer.' }, dimension: 'H' }, { text: { es: 'Trabajo en proyectos que generan impacto y que otros no podrían hacer sin este capital.', en: 'I work on projects that generate impact and that others couldn\'t do without this capital.', fr: 'Je travaille sur des projets qui génèrent un impact et que d\'autres ne pourraient pas faire sans ce capital.', de: 'Ich arbeite an Projekten, die Wirkung erzielen und die andere ohne dieses Kapital nicht tun könnten.', it: 'Lavoro su progetti che generano impatto e che altri non potrebbero fare senza questo capitale.', pt: 'Trabalho em projetos que geram impacto e que outros não poderiam fazer sem esse capital.' }, dimension: 'G' }, { text: { es: 'Trabajo para construir más. El dinero es poder y el poder se construye.', en: 'I work to build more. Money is power and power is built.', fr: 'Je travaille pour construire davantage. L\'argent est pouvoir et le pouvoir se construit.', de: 'Ich arbeite, um mehr aufzubauen. Geld ist Macht und Macht wird aufgebaut.', it: 'Lavoro per costruire di più. Il denaro è potere e il potere si costruisce.', pt: 'Trabalho para construir mais. O dinheiro é poder e o poder se constrói.' }, dimension: 'P' }, { text: { es: 'Trabajo en proyectos de largo plazo que quiero que sobrevivan cuando ya no esté.', en: 'I work on long-term projects that I want to survive when I\'m gone.', fr: 'Je travaille sur des projets à long terme que je veux voir survivre quand je ne serai plus là.', de: 'Ich arbeite an langfristigen Projekten, die ich mir wünsche, dass sie überleben, wenn ich nicht mehr da bin.', it: 'Lavoro su progetti a lungo termine che voglio sopravvivano quando non ci sarò più.', pt: 'Trabalho em projetos de longo prazo que quero que sobrevivam quando não estiver mais aqui.' }, dimension: 'L' }] },
        { id: 5, situation: { es: 'Alguien que te cayó mal en el pasado ahora necesita ayuda.', en: 'Someone you disliked in the past now needs help.', fr: 'Quelqu\'un qui ne vous plaisait pas dans le passé a maintenant besoin d\'aide.', de: 'Jemand, den du in der Vergangenheit nicht mochtest, braucht jetzt Hilfe.', it: 'Qualcuno che non ti piaceva in passato ora ha bisogno di aiuto.', pt: 'Alguém com quem você não se dava bem no passado agora precisa de ajuda.' }, options: [{ text: { es: 'Dependiendo de qué tan mal me cayó, quizás le doy una oportunidad de redención.', en: 'Depending on how much I disliked them, maybe I give them a chance at redemption.', fr: 'Selon à quel point il/elle ne me plaisait pas, peut-être que je lui donne une chance de rédemption.', de: 'Abhängig davon, wie sehr ich sie nicht mochte, gebe ich ihnen vielleicht eine Chance zur Wiedergutmachung.', it: 'A seconda di quanto non mi piaceva, forse gli/le do una possibilità di redenzione.', pt: 'Dependendo do quanto não gostava dela, talvez lhe dê uma oportunidade de redenção.' }, dimension: 'H' }, { text: { es: 'Lo ayudo. El dinero me da la libertad de ser generoso incluso con los que no lo merecen.', en: 'I help them. Money gives me the freedom to be generous even with those who don\'t deserve it.', fr: 'Je l\'aide. L\'argent me donne la liberté d\'être généreux même avec ceux qui ne le méritent pas.', de: 'Ich helfe ihnen. Geld gibt mir die Freiheit, großzügig zu sein, auch gegenüber denen, die es nicht verdienen.', it: 'Lo/La aiuto. Il denaro mi dà la libertà di essere generoso anche con chi non lo merita.', pt: 'Ajudo. O dinheiro me dá a liberdade de ser generoso mesmo com quem não merece.' }, dimension: 'G' }, { text: { es: 'No necesito mezclarme con gente que no me suma.', en: 'I don\'t need to mix with people who don\'t add value to me.', fr: 'Je n\'ai pas besoin de me mêler à des gens qui ne m\'apportent rien.', de: 'Ich muss mich nicht mit Menschen abgeben, die mir nichts geben.', it: 'Non ho bisogno di mescolarmi con persone che non mi apportano nulla.', pt: 'Não preciso me misturar com pessoas que não me acrescentam.' }, dimension: 'P' }, { text: { es: 'Lo evalúo según si tiene algo que ver con mis proyectos.', en: 'I evaluate it based on whether it has anything to do with my projects.', fr: 'Je l\'évalue selon si cela a quelque chose à voir avec mes projets.', de: 'Ich bewerte es danach, ob es etwas mit meinen Projekten zu tun hat.', it: 'Lo valuto in base al se ha qualcosa a che fare con i miei progetti.', pt: 'Avalio conforme se tem alguma relação com meus projetos.' }, dimension: 'L' }] },
        { id: 6, situation: { es: '¿Qué haces con el tiempo que el dinero te libera?', en: 'What do you do with the time that money frees up for you?', fr: 'Que faites-vous avec le temps que l\'argent vous libère?', de: 'Was machst du mit der Zeit, die dir das Geld freisetzt?', it: 'Cosa fai con il tempo che il denaro ti libera?', pt: 'O que você faz com o tempo que o dinheiro te libera?' }, options: [{ text: { es: 'Viajes, experiencias, placeres que siempre quise tener.', en: 'Travel, experiences, pleasures I always wanted to have.', fr: 'Voyages, expériences, plaisirs que j\'ai toujours voulu avoir.', de: 'Reisen, Erlebnisse, Freuden, die ich schon immer haben wollte.', it: 'Viaggi, esperienze, piaceri che ho sempre voluto avere.', pt: 'Viagens, experiências, prazeres que sempre quis ter.' }, dimension: 'H' }, { text: { es: 'Me dedico a personas y causas que necesitan mi tiempo tanto como mi dinero.', en: 'I dedicate myself to people and causes that need my time as much as my money.', fr: 'Je me consacre à des personnes et des causes qui ont autant besoin de mon temps que de mon argent.', de: 'Ich widme mich Menschen und Anliegen, die meine Zeit genauso brauchen wie mein Geld.', it: 'Mi dedico a persone e cause che hanno bisogno del mio tempo tanto quanto del mio denaro.', pt: 'Me dedico a pessoas e causas que precisam do meu tempo tanto quanto do meu dinheiro.' }, dimension: 'G' }, { text: { es: 'Me estrategifico: aprendo, hago contactos, construyo más influencia.', en: 'I strategize: I learn, network, build more influence.', fr: 'Je me stratégise: j\'apprends, je fais des contacts, je construis plus d\'influence.', de: 'Ich strategisiere: Ich lerne, knüpfe Kontakte, baue mehr Einfluss auf.', it: 'Mi stratifico: imparo, faccio contatti, costruisco più influenza.', pt: 'Me estrategifico: aprendo, faço contatos, construo mais influência.' }, dimension: 'P' }, { text: { es: 'Trabajo en el proyecto que quiero dejar como legado.', en: 'I work on the project I want to leave as my legacy.', fr: 'Je travaille sur le projet que je veux laisser en héritage.', de: 'Ich arbeite an dem Projekt, das ich als mein Vermächtnis hinterlassen möchte.', it: 'Lavoro sul progetto che voglio lasciare come eredità.', pt: 'Trabalho no projeto que quero deixar como legado.' }, dimension: 'L' }] },
        { id: 7, situation: { es: '¿Cómo tratas a las personas que trabajan para ti?', en: 'How do you treat the people who work for you?', fr: 'Comment traitez-vous les personnes qui travaillent pour vous?', de: 'Wie behandelst du die Menschen, die für dich arbeiten?', it: 'Come tratti le persone che lavorano per te?', pt: 'Como você trata as pessoas que trabalham para você?' }, options: [{ text: { es: 'Bien, pero claramente somos de mundos diferentes. La jerarquía es real.', en: 'Well, but clearly we are from different worlds. The hierarchy is real.', fr: 'Bien, mais clairement nous sommes de mondes différents. La hiérarchie est réelle.', de: 'Gut, aber wir kommen klar aus verschiedenen Welten. Die Hierarchie ist real.', it: 'Bene, ma chiaramente siamo di mondi diversi. La gerarchia è reale.', pt: 'Bem, mas claramente somos de mundos diferentes. A hierarquia é real.' }, dimension: 'H' }, { text: { es: 'Con mucho respeto y generosidad. El dinero me da la posibilidad de ser un buen empleador.', en: 'With great respect and generosity. Money gives me the possibility of being a good employer.', fr: 'Avec beaucoup de respect et de générosité. L\'argent me donne la possibilité d\'être un bon employeur.', de: 'Mit großem Respekt und Großzügigkeit. Geld gibt mir die Möglichkeit, ein guter Arbeitgeber zu sein.', it: 'Con molto rispetto e generosità. Il denaro mi dà la possibilità di essere un buon datore di lavoro.', pt: 'Com muito respeito e generosidade. O dinheiro me dá a possibilidade de ser um bom empregador.' }, dimension: 'G' }, { text: { es: 'Con respeto profesional. La relación es transaccional y está bien que lo sea.', en: 'With professional respect. The relationship is transactional and that\'s fine.', fr: 'Avec respect professionnel. La relation est transactionnelle et c\'est bien ainsi.', de: 'Mit professionellem Respekt. Die Beziehung ist transaktional und das ist in Ordnung.', it: 'Con rispetto professionale. Il rapporto è transazionale ed è giusto che lo sia.', pt: 'Com respeito profissional. A relação é transacional e tudo bem que seja assim.' }, dimension: 'P' }, { text: { es: 'Como socios en algo que quiero que dure. Su bienestar importa para el proyecto.', en: 'As partners in something I want to last. Their wellbeing matters for the project.', fr: 'Comme des associés dans quelque chose que je veux voir durer. Leur bien-être compte pour le projet.', de: 'Als Partner in etwas, das ich dauerhaft haben möchte. Ihr Wohlbefinden ist wichtig für das Projekt.', it: 'Come soci in qualcosa che voglio duri. Il loro benessere conta per il progetto.', pt: 'Como sócios em algo que quero que dure. O bem-estar deles importa para o projeto.' }, dimension: 'L' }] },
        { id: 8, situation: { es: '¿Cuánto de tu fortuna vas a donar?', en: 'How much of your fortune are you going to donate?', fr: 'Combien de votre fortune allez-vous donner?', de: 'Wie viel von deinem Vermögen wirst du spenden?', it: 'Quanto della tua fortuna donerai?', pt: 'Quanto da sua fortuna você vai doar?' }, options: [{ text: { es: 'Algo simbólico. No soy una ONG.', en: 'Something symbolic. I\'m not an NGO.', fr: 'Quelque chose de symbolique. Je ne suis pas une ONG.', de: 'Etwas Symbolisches. Ich bin keine NGO.', it: 'Qualcosa di simbolico. Non sono una ONG.', pt: 'Algo simbólico. Não sou uma ONG.' }, dimension: 'H' }, { text: { es: 'Una parte significativa. Con tanto dinero, sería inmoral no hacerlo.', en: 'A significant portion. With so much money, it would be immoral not to.', fr: 'Une partie significative. Avec autant d\'argent, ne pas le faire serait immoral.', de: 'Ein erheblicher Teil. Mit so viel Geld wäre es unmoralisch, es nicht zu tun.', it: 'Una parte significativa. Con così tanti soldi, sarebbe immorale non farlo.', pt: 'Uma parte significativa. Com tanto dinheiro, seria imoral não fazê-lo.' }, dimension: 'G' }, { text: { es: 'Lo necesario para tener buena reputación pública.', en: 'Enough to maintain a good public reputation.', fr: 'Le nécessaire pour avoir une bonne réputation publique.', de: 'Das Nötige, um einen guten öffentlichen Ruf zu haben.', it: 'Quanto basta per avere una buona reputazione pubblica.', pt: 'O necessário para ter boa reputação pública.' }, dimension: 'P' }, { text: { es: 'Una parte grande pero en causas específicas que elijo con criterio.', en: 'A large portion but to specific causes I choose deliberately.', fr: 'Une grande partie mais pour des causes spécifiques que je choisis avec discernement.', de: 'Ein großer Teil, aber für spezifische Anliegen, die ich gezielt auswähle.', it: 'Una parte grande ma per cause specifiche che scelgo con criterio.', pt: 'Uma parte grande, mas para causas específicas que escolho com critério.' }, dimension: 'L' }] },
        { id: 9, situation: { es: 'Una persona te pide dinero para un proyecto que no te convence.', en: 'Someone asks you for money for a project you\'re not convinced by.', fr: 'Une personne vous demande de l\'argent pour un projet qui ne vous convainc pas.', de: 'Jemand bittet dich um Geld für ein Projekt, das dich nicht überzeugt.', it: 'Una persona ti chiede soldi per un progetto che non ti convince.', pt: 'Uma pessoa te pede dinheiro para um projeto que não te convence.' }, options: [{ text: { es: 'No lo financio. Prefiero gastar mi dinero en cosas que disfruto.', en: 'I don\'t fund it. I prefer to spend my money on things I enjoy.', fr: 'Je ne le finance pas. Je préfère dépenser mon argent sur des choses que j\'apprécie.', de: 'Ich finanziere es nicht. Ich gebe mein Geld lieber für Dinge aus, die ich genieße.', it: 'Non lo finanzo. Preferisco spendere i miei soldi in cose che mi piacciono.', pt: 'Não financio. Prefiro gastar meu dinheiro em coisas que disfruto.' }, dimension: 'H' }, { text: { es: 'Le doy algo de todas formas. La generosidad no siempre requiere convencerse.', en: 'I give them something anyway. Generosity doesn\'t always require being convinced.', fr: 'Je lui donne quelque chose quand même. La générosité ne nécessite pas toujours d\'être convaincu.', de: 'Ich gebe ihnen trotzdem etwas. Großzügigkeit erfordert nicht immer Überzeugung.', it: 'Gli/Le do qualcosa comunque. La generosità non richiede sempre di essere convinti.', pt: 'Dou algo de qualquer maneira. A generosidade nem sempre requer convencimento.' }, dimension: 'G' }, { text: { es: 'No lo financio. Mi dinero va a proyectos que controlo.', en: 'I don\'t fund it. My money goes to projects I control.', fr: 'Je ne le finance pas. Mon argent va à des projets que je contrôle.', de: 'Ich finanziere es nicht. Mein Geld fließt in Projekte, die ich kontrolliere.', it: 'Non lo finanzo. I miei soldi vanno a progetti che controllo.', pt: 'Não financio. Meu dinheiro vai para projetos que controlo.' }, dimension: 'P' }, { text: { es: 'No lo financio, pero le explico por qué y le ofrezco feedback si le sirve.', en: 'I don\'t fund it, but I explain why and offer feedback if it\'s useful to them.', fr: 'Je ne le finance pas, mais je lui explique pourquoi et je lui offre des commentaires si cela lui est utile.', de: 'Ich finanziere es nicht, aber ich erkläre, warum, und biete Feedback an, wenn es nützlich ist.', it: 'Non lo finanzo, ma spiego perché e offro feedback se gli/le è utile.', pt: 'Não financio, mas explico o motivo e ofereço feedback se for útil.' }, dimension: 'L' }] },
        { id: 10, situation: { es: 'En tu vejez, ¿qué hiciste con tu dinero?', en: 'In your old age, what did you do with your money?', fr: 'Dans votre vieillesse, qu\'avez-vous fait avec votre argent?', de: 'In deinem Alter, was hast du mit deinem Geld gemacht?', it: 'Nella tua vecchiaia, cosa hai fatto con i tuoi soldi?', pt: 'Na sua velhice, o que você fez com o seu dinheiro?' }, options: [{ text: { es: 'Viví extraordinariamente bien. Cada placer que quise, lo tuve.', en: 'I lived extraordinarily well. Every pleasure I wanted, I had.', fr: 'J\'ai vécu extraordinairement bien. Chaque plaisir que je voulais, je l\'ai eu.', de: 'Ich lebte außerordentlich gut. Jedes Vergnügen, das ich wollte, hatte ich.', it: 'Ho vissuto straordinariamente bene. Ogni piacere che ho voluto, l\'ho avuto.', pt: 'Vivi extraordinariamente bem. Cada prazer que quis, tive.' }, dimension: 'H' }, { text: { es: 'Cambié la vida de personas concretas que nunca olvidaré.', en: 'I changed the lives of specific people I will never forget.', fr: 'J\'ai changé la vie de personnes concrètes que je n\'oublierai jamais.', de: 'Ich veränderte das Leben konkreter Menschen, die ich niemals vergessen werde.', it: 'Ho cambiato la vita di persone concrete che non dimenticherò mai.', pt: 'Mudei a vida de pessoas concretas que nunca esquecerei.' }, dimension: 'G' }, { text: { es: 'Construí algo que tiene influencia real sobre cómo funciona el mundo.', en: 'I built something that has real influence over how the world works.', fr: 'J\'ai construit quelque chose qui a une influence réelle sur le fonctionnement du monde.', de: 'Ich habe etwas aufgebaut, das realen Einfluss darauf hat, wie die Welt funktioniert.', it: 'Ho costruito qualcosa che ha influenza reale su come funziona il mondo.', pt: 'Construí algo que tem influência real sobre como o mundo funciona.' }, dimension: 'P' }, { text: { es: 'Dejé algo que sobrevive: una fundación, una empresa, una obra que importa.', en: 'I left something that survives: a foundation, a company, a work that matters.', fr: 'J\'ai laissé quelque chose qui survit: une fondation, une entreprise, une œuvre qui compte.', de: 'Ich habe etwas hinterlassen, das überlebt: eine Stiftung, ein Unternehmen, ein Werk, das Bedeutung hat.', it: 'Ho lasciato qualcosa che sopravvive: una fondazione, un\'impresa, un\'opera che conta.', pt: 'Deixei algo que sobrevive: uma fundação, uma empresa, uma obra que importa.' }, dimension: 'L' }] },
      ],
      characters: [
        { name: { es: 'El Epicúreo Rico', en: 'The Wealthy Epicurean', fr: 'L\'Épicurien Riche', de: 'Der Wohlhabende Epikureer', it: 'L\'Epicureo Ricco', pt: 'O Epicurista Rico' }, dimensions: ['H'], photo: '/characters/epicurean-rich.jpg', description: { es: 'El dinero existe para disfrutarlo. Sin disculpas.', en: 'Money exists to be enjoyed. No apologies.', fr: 'L\'argent existe pour être apprécié. Sans excuses.', de: 'Geld existiert, um genossen zu werden. Ohne Entschuldigungen.', it: 'Il denaro esiste per essere goduto. Senza scuse.', pt: 'O dinheiro existe para ser desfrutado. Sem desculpas.' }, philosophy: { es: 'Para ti, el dinero es la herramienta definitiva del placer. No te disculpas por ello. Viviste un tiempo sin esos recursos — ahora que los tienes, los disfrutas. La única pregunta que vale es si eso te hace feliz.', en: 'For you, money is the ultimate tool of pleasure. You don\'t apologize for it. You lived for a time without those resources — now that you have them, you enjoy them. The only question that matters is whether that makes you happy.', fr: 'Pour vous, l\'argent est l\'outil ultime du plaisir. Vous ne vous en excusez pas. Vous avez vécu un temps sans ces ressources — maintenant que vous les avez, vous en profitez. La seule question qui vaille est de savoir si cela vous rend heureux.', de: 'Für dich ist Geld das ultimative Werkzeug des Genusses. Du entschuldigst dich nicht dafür. Du hast eine Zeit ohne diese Mittel gelebt — jetzt, da du sie hast, genießt du sie. Die einzige Frage, die zählt, ist, ob dich das glücklich macht.', it: 'Per te, il denaro è lo strumento definitivo del piacere. Non ti scusi per questo. Hai vissuto per un periodo senza quelle risorse — ora che le hai, le godi. La sola domanda che conta è se questo ti rende felice.', pt: 'Para você, o dinheiro é a ferramenta definitiva do prazer. Você não se desculpa por isso. Você viveu um tempo sem esses recursos — agora que os tem, os desfruta. A única questão que vale é se isso te faz feliz.' } },
        { name: { es: 'El Filántropo Auténtico', en: 'The Authentic Philanthropist', fr: 'Le Philanthrope Authentique', de: 'Der Authentische Philanthrop', it: 'Il Filantropo Autentico', pt: 'O Filantropo Autêntico' }, dimensions: ['G'], photo: '/characters/authentic-philanthropist.jpg', description: { es: 'El dinero solo tiene sentido si cambia vidas ajenas.', en: 'Money only makes sense if it changes other people\'s lives.', fr: 'L\'argent n\'a de sens que s\'il change la vie des autres.', de: 'Geld macht nur Sinn, wenn es das Leben anderer verändert.', it: 'Il denaro ha senso solo se cambia la vita degli altri.', pt: 'O dinheiro só faz sentido se mudar a vida dos outros.' }, philosophy: { es: 'Para ti, acumular riqueza sin distribuirla es una forma de fracaso. No porque sea una obligación — sino porque la generosidad te da un placer real. Ver el impacto concreto de tu dinero vale más que cualquier lujo.', en: 'For you, accumulating wealth without distributing it is a form of failure. Not because it\'s an obligation — but because generosity gives you real pleasure. Seeing the concrete impact of your money is worth more than any luxury.', fr: 'Pour vous, accumuler de la richesse sans la distribuer est une forme d\'échec. Non pas parce que c\'est une obligation — mais parce que la générosité vous procure un plaisir réel. Voir l\'impact concret de votre argent vaut plus que n\'importe quel luxe.', de: 'Für dich ist das Anhäufen von Reichtum ohne ihn zu verteilen eine Form des Scheiterns. Nicht weil es eine Pflicht ist — sondern weil Großzügigkeit dir echte Freude bereitet. Den konkreten Impact deines Geldes zu sehen ist mehr wert als jeder Luxus.', it: 'Per te, accumulare ricchezza senza distribuirla è una forma di fallimento. Non perché sia un obbligo — ma perché la generosità ti dà un piacere reale. Vedere l\'impatto concreto del tuo denaro vale più di qualsiasi lusso.', pt: 'Para você, acumular riqueza sem distribuí-la é uma forma de fracasso. Não porque seja uma obrigação — mas porque a generosidade te dá um prazer real. Ver o impacto concreto do seu dinheiro vale mais do que qualquer luxo.' } },
        { name: { es: 'El Constructor de Poder', en: 'The Power Builder', fr: 'Le Constructeur de Pouvoir', de: 'Der Machtbauer', it: 'Il Costruttore di Potere', pt: 'O Construtor de Poder' }, dimensions: ['P'], photo: '/characters/power-builder.jpg', description: { es: 'El dinero es el primer escalón. El poder es el destino.', en: 'Money is the first step. Power is the destination.', fr: 'L\'argent est le premier échelon. Le pouvoir est la destination.', de: 'Geld ist die erste Stufe. Macht ist das Ziel.', it: 'Il denaro è il primo scalino. Il potere è la destinazione.', pt: 'O dinheiro é o primeiro degrau. O poder é o destino.' }, philosophy: { es: 'Para ti, el dinero es un medio, no un fin. Lo que buscas es influencia real sobre cómo funcionan las cosas. Eso puede ser bueno o problemático, dependiendo de qué hagas con ese poder.', en: 'For you, money is a means, not an end. What you seek is real influence over how things work. That can be good or problematic, depending on what you do with that power.', fr: 'Pour vous, l\'argent est un moyen, pas une fin. Ce que vous cherchez, c\'est une influence réelle sur le fonctionnement des choses. Cela peut être bien ou problématique, selon ce que vous faites de ce pouvoir.', de: 'Für dich ist Geld ein Mittel, kein Zweck. Was du suchst, ist realer Einfluss darauf, wie die Dinge funktionieren. Das kann gut oder problematisch sein, je nachdem, was du mit dieser Macht machst.', it: 'Per te, il denaro è un mezzo, non un fine. Quello che cerchi è influenza reale su come funzionano le cose. Questo può essere buono o problematico, a seconda di cosa fai con quel potere.', pt: 'Para você, o dinheiro é um meio, não um fim. O que você busca é influência real sobre como as coisas funcionam. Isso pode ser bom ou problemático, dependendo do que você faz com esse poder.' } },
        { name: { es: 'El Arquitecto del Legado', en: 'The Legacy Architect', fr: 'L\'Architecte de l\'Héritage', de: 'Der Vermächtnis-Architekt', it: 'L\'Architetto del Lascito', pt: 'O Arquiteto do Legado' }, dimensions: ['L'], photo: '/characters/legacy-architect.jpg', description: { es: 'Construye para que algo suyo sobreviva cuando ya no esté.', en: 'Builds so that something of theirs survives when they are gone.', fr: 'Construit pour que quelque chose de lui/elle survive quand il/elle ne sera plus là.', de: 'Baut, damit etwas von ihm/ihr überlebt, wenn er/sie nicht mehr da ist.', it: 'Costruisce perché qualcosa di suo sopravviva quando non ci sarà più.', pt: 'Constrói para que algo seu sobreviva quando não estiver mais aqui.' }, philosophy: { es: 'Para ti, la verdadera riqueza es dejar algo que dure. No una fortuna heredada — una obra, un sistema, una idea que siga funcionando cuando ya no estés. Esa es la única forma de inmortalidad que te parece real.', en: 'For you, true wealth is leaving something that lasts. Not an inherited fortune — a work, a system, an idea that keeps functioning when you\'re gone. That is the only form of immortality that seems real to you.', fr: 'Pour vous, la vraie richesse consiste à laisser quelque chose qui dure. Pas une fortune héritée — une œuvre, un système, une idée qui continue à fonctionner quand vous ne serez plus là. C\'est la seule forme d\'immortalité qui vous semble réelle.', de: 'Für dich ist der wahre Reichtum, etwas zu hinterlassen, das dauert. Kein geerbtes Vermögen — ein Werk, ein System, eine Idee, die weiter funktioniert, wenn du nicht mehr da bist. Das ist die einzige Form der Unsterblichkeit, die dir real erscheint.', it: 'Per te, la vera ricchezza è lasciare qualcosa che duri. Non una fortuna ereditata — un\'opera, un sistema, un\'idea che continui a funzionare quando non ci sarai più. Questa è la sola forma di immortalità che ti sembra reale.', pt: 'Para você, a verdadeira riqueza é deixar algo que dure. Não uma fortuna herdada — uma obra, um sistema, uma ideia que continue funcionando quando você não estiver mais aqui. Essa é a única forma de imortalidade que lhe parece real.' } },
        { name: { es: 'El Hedonista Generoso', en: 'The Generous Hedonist', fr: 'L\'Hédoniste Généreux', de: 'Der Großzügige Hedonist', it: 'L\'Edonista Generoso', pt: 'O Hedonista Generoso' }, dimensions: ['H', 'G'], photo: '/characters/hedonist-generous.jpg', description: { es: 'Vive bien y ayuda a que otros vivan bien.', en: 'Lives well and helps others live well.', fr: 'Vit bien et aide les autres à bien vivre.', de: 'Lebt gut und hilft anderen, gut zu leben.', it: 'Vive bene e aiuta gli altri a vivere bene.', pt: 'Vive bem e ajuda os outros a viverem bem.' }, philosophy: { es: 'No hay contradicción entre disfrutar y dar. Disfrutas tu dinero sin culpa y también lo distribuyes sin renunciar. Esa combinación requiere dinero suficiente y también una claridad sobre cuánto es suficiente para uno mismo.', en: 'There is no contradiction between enjoying and giving. You enjoy your money without guilt and also distribute it without giving it all up. That combination requires enough money and also clarity about how much is enough for oneself.', fr: 'Il n\'y a pas de contradiction entre jouir et donner. Vous profitez de votre argent sans culpabilité et le distribuez aussi sans y renoncer. Cette combinaison nécessite suffisamment d\'argent et aussi une clarté sur ce qui est suffisant pour soi-même.', de: 'Es gibt keinen Widerspruch zwischen Genießen und Geben. Du genießt dein Geld ohne Schuldgefühle und verteilst es auch ohne Verzicht. Diese Kombination erfordert genug Geld und auch Klarheit darüber, was für einen selbst genug ist.', it: 'Non c\'è contraddizione tra godere e dare. Godi del tuo denaro senza sensi di colpa e lo distribuisci anche senza rinunciare. Questa combinazione richiede denaro sufficiente e anche chiarezza su quanto è abbastanza per se stessi.', pt: 'Não há contradição entre desfrutar e dar. Você desfruta do seu dinheiro sem culpa e também o distribui sem renunciar. Essa combinação requer dinheiro suficiente e também clareza sobre quanto é o suficiente para si mesmo.' } },
        { name: { es: 'El Poderoso Generoso', en: 'The Generous Powerful', fr: 'Le Puissant Généreux', de: 'Der Großzügige Mächtige', it: 'Il Potente Generoso', pt: 'O Poderoso Generoso' }, dimensions: ['G', 'P'], photo: '/characters/powerful-generous.jpg', description: { es: 'Usa el poder para generar impacto a mayor escala.', en: 'Uses power to generate impact on a larger scale.', fr: 'Utilise le pouvoir pour générer un impact à plus grande échelle.', de: 'Nutzt Macht, um Wirkung in größerem Maßstab zu erzielen.', it: 'Usa il potere per generare impatto su scala maggiore.', pt: 'Usa o poder para gerar impacto em maior escala.' }, philosophy: { es: 'Para ti, la generosidad más eficiente requiere poder. No es suficiente dar dinero — es necesario tener influencia sobre los sistemas que perpetúan la desigualdad. El poder como herramienta del bien.', en: 'For you, the most efficient generosity requires power. It\'s not enough to give money — you need to have influence over the systems that perpetuate inequality. Power as a tool for good.', fr: 'Pour vous, la générosité la plus efficace nécessite du pouvoir. Il ne suffit pas de donner de l\'argent — il est nécessaire d\'avoir de l\'influence sur les systèmes qui perpétuent l\'inégalité. Le pouvoir comme outil du bien.', de: 'Für dich erfordert die effizienteste Großzügigkeit Macht. Es reicht nicht, Geld zu geben — du musst Einfluss auf die Systeme haben, die Ungleichheit aufrechterhalten. Macht als Werkzeug des Guten.', it: 'Per te, la generosità più efficiente richiede potere. Non basta dare denaro — è necessario avere influenza sui sistemi che perpetuano la disuguaglianza. Il potere come strumento del bene.', pt: 'Para você, a generosidade mais eficiente requer poder. Não basta dar dinheiro — é necessário ter influência sobre os sistemas que perpetuam a desigualdade. O poder como ferramenta do bem.' } },
        { name: { es: 'El Constructor de Sistemas', en: 'The Systems Builder', fr: 'Le Constructeur de Systèmes', de: 'Der Systemerbauer', it: 'Il Costruttore di Sistemi', pt: 'O Construtor de Sistemas' }, dimensions: ['P', 'L'], photo: '/characters/systems-builder.jpg', description: { es: 'Construye estructuras que generan poder e impacto duradero.', en: 'Builds structures that generate power and lasting impact.', fr: 'Construit des structures qui génèrent du pouvoir et un impact durable.', de: 'Baut Strukturen auf, die Macht und dauerhaften Impact erzeugen.', it: 'Costruisce strutture che generano potere e impatto duraturo.', pt: 'Constrói estruturas que geram poder e impacto duradouro.' }, philosophy: { es: 'Combinas la ambición de poder con la visión de largo plazo. No te interesa el impacto inmediato — te interesa construir algo que siga funcionando cuando ya no estés para verlo.', en: 'You combine the ambition for power with a long-term vision. You\'re not interested in immediate impact — you\'re interested in building something that keeps working when you\'re no longer there to see it.', fr: 'Vous combinez l\'ambition du pouvoir avec la vision à long terme. Ce n\'est pas l\'impact immédiat qui vous intéresse — c\'est construire quelque chose qui continue à fonctionner quand vous ne serez plus là pour le voir.', de: 'Du kombinierst den Machtehrgeiz mit der langfristigen Vision. Du interessierst dich nicht für unmittelbare Wirkung — du interessierst dich dafür, etwas aufzubauen, das weiter funktioniert, wenn du nicht mehr da bist, um es zu sehen.', it: 'Combini l\'ambizione di potere con la visione a lungo termine. Non ti interessa l\'impatto immediato — ti interessa costruire qualcosa che continui a funzionare quando non ci sarai più per vederlo.', pt: 'Você combina a ambição de poder com a visão de longo prazo. Não lhe interessa o impacto imediato — lhe interessa construir algo que continue funcionando quando você não estiver mais aqui para vê-lo.' } },
        { name: { es: 'El Filántropo con Legado', en: 'The Philanthropist with a Legacy', fr: 'Le Philanthrope avec un Héritage', de: 'Der Philanthrop mit Vermächtnis', it: 'Il Filantropo con un Lascito', pt: 'O Filantropo com Legado' }, dimensions: ['G', 'L'], photo: '/characters/philanthropist-legacy.jpg', description: { es: 'Genera impacto ahora y construye para que ese impacto dure.', en: 'Creates impact now and builds so that impact lasts.', fr: 'Génère un impact maintenant et construit pour que cet impact dure.', de: 'Erzeugt jetzt Wirkung und baut, damit diese Wirkung dauert.', it: 'Genera impatto ora e costruisce affinché quell\'impatto duri.', pt: 'Gera impacto agora e constrói para que esse impacto dure.' }, philosophy: { es: 'Tu generosidad no es espontánea — es estratégica. No es fría — es efectiva. Quieres que el bien que haces con tu dinero sobreviva y se multiplique. Eso requiere tanto corazón como cabeza.', en: 'Your generosity is not spontaneous — it\'s strategic. It\'s not cold — it\'s effective. You want the good you do with your money to survive and multiply. That requires both heart and mind.', fr: 'Votre générosité n\'est pas spontanée — elle est stratégique. Elle n\'est pas froide — elle est efficace. Vous voulez que le bien que vous faites avec votre argent survive et se multiplie. Cela nécessite autant de cœur que de tête.', de: 'Deine Großzügigkeit ist nicht spontan — sie ist strategisch. Sie ist nicht kalt — sie ist effektiv. Du willst, dass das Gute, das du mit deinem Geld tust, überlebt und sich multipliziert. Das erfordert sowohl Herz als auch Verstand.', it: 'La tua generosità non è spontanea — è strategica. Non è fredda — è efficace. Vuoi che il bene che fai con il tuo denaro sopravviva e si moltiplichi. Ciò richiede sia cuore che mente.', pt: 'Sua generosidade não é espontânea — é estratégica. Não é fria — é eficaz. Você quer que o bem que faz com o seu dinheiro sobreviva e se multiplique. Isso requer tanto coração quanto cabeça.' } },
      ],
    },
  });
}
